+fn is_potential_ready_candidate(issue: &StatsIssueRow, now: &chrono::DateTime<Utc>) -> bool {
+    issue.status == Status::Open
+        && !issue.ephemeral
+        && !is_wisp_issue_id(&issue.id)
+        && !issue.pinned
+        && !issue.is_template
+        && issue
+            .defer_until
+            .as_ref()
+            .is_none_or(|defer_until| defer_until <= now)
+}
